    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xCC77609AAD89B5B5ULL + 0xED1AD3AFEA76AA10ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xB21B3F17926E9B23ULL + 0xD5A4F10CB436DD64ULL);
