            aOrbiterA = ((((aWandererJ + RotL64(aIngress, 24U)) + RotL64(aCarry, 19U)) + 2713390028205980131U) + aOrbiterAssignSaltD[((aIndex + 19U)) & S_SALT1]) + aNonceWordM;
