            //
            aOrbiterD = (aOrbiterD + aOrbiterH) + 15643806354203381016U;
            aOrbiterG = ((aOrbiterG ^ aOrbiterD) ^ 446144915352944965U) ^ aNonceWordP;
            aOrbiterG = RotL64((aOrbiterG * 5020970857321930135U), 23U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterG) + 6721319268047045273U;
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 8896318144720483973U;
            aOrbiterC = RotL64((aOrbiterC * 6437932738434506665U), 57U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterF) + 15226293935954273468U) + aNonceWordB;
            aOrbiterE = (((aOrbiterE ^ aOrbiterI) ^ 5345457951126147401U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 16U)) & S_SALT1]) ^ aNonceWordL;
            aOrbiterE = RotL64((aOrbiterE * 16838629051800478225U), 47U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterA) + 4550977026085506223U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterB) ^ 3514750647356705708U;
