            aOrbiterJ = RotL64((aOrbiterJ * 9140041919023873289U), 3U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterB) + 7490654454511905883U;
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 2599040226537412293U;
            aOrbiterI = RotL64((aOrbiterI * 430711236244284089U), 39U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 7431918937312615228U;
