            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 13427576767089577474U;
            aOrbiterH = (((aOrbiterH ^ aOrbiterJ) ^ 106137745998249013U) ^ aOrbiterUpdateSaltC[((aIndex + 17U)) & S_SALT1]) ^ aNonceWordA;
            aOrbiterH = RotL64((aOrbiterH * 6193255892454445903U), 19U);
            //
            aIngress = RotL64(aOrbiterD, 53U) ^ aOrbiterF;
