            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererK = aWandererK ^ ((RotL64(aCross, 6U) + RotL64(aOrbiterK, 11U)) + aOrbiterF);
            aWandererI = aWandererI + (((((RotL64(aScatter, 57U) + aOrbiterJ) + RotL64(aOrbiterD, 19U)) + RotL64(aCarry, 21U)) + aNonceWordH) + aWandererUpdateSaltF[((aIndex + 25U)) & S_SALT1]);
