            //
            aOrbiterF = (aOrbiterF + aOrbiterD) + 1974523029356026751U;
            aOrbiterG = (aOrbiterG ^ aOrbiterF) ^ 9086114482741017876U;
            aOrbiterG = RotL64((aOrbiterG * 10781174966878385559U), 23U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 6037554433810448023U;
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 15915269434441626085U;
            aOrbiterD = RotL64((aOrbiterD * 7389224676326500121U), 29U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterB) + 703488676390902724U;
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 18171816670350134888U;
            aOrbiterH = RotL64((aOrbiterH * 13724084218403525907U), 39U);
            //
            aOrbiterJ = (((aOrbiterJ + aOrbiterF) + 10598331815924882476U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 3U)) & S_SALT1]) + aNonceWordD;
            aOrbiterB = ((aOrbiterB ^ aOrbiterJ) ^ 12100445244153546473U) ^ aOrbiterUpdateSaltB[((aIndex + 13U)) & S_SALT1];
