            aWandererC = aWandererC ^ (((RotL64(aPrevious, 37U) + RotL64(aOrbiterI, 39U)) + aOrbiterG) + aPhaseGWandererUpdateSaltD[((aIndex + 13U)) & S_SALT1]);
            aWandererJ = aWandererJ + (((RotL64(aScatter, 26U) + RotL64(aOrbiterF, 21U)) + aOrbiterG) + RotL64(aCarry, 19U));
